addEventListener("fetch", event => {
  const request = event.request;
  const url = new URL(request.url);
  const ttl = parseInt(url.searchParams.get("ttl"));
  const cacheKey = url.searchParams.get("cache_key");

  if (isNaN(ttl) || !cacheKey) {
    return event.respondWith(new Response("Invalid request", { status: 400 }));
  }

  // Validate untrusted input and use secure platform APIs
  const cache = caches.default;
  const cacheControl = new CacheControl({ ttl });
  const cachedResponse = await cache.match(cacheKey, { cacheControl });

  if (cachedResponse) {
    return event.respondWith(cachedResponse);
  }

  // Apply least privilege and explicit allowlists where relevant
  const fetchOptions = {
    headers: {
      "Content-Type": "application/json",
    },
  };

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const response = await fetch(request.url, fetchOptions);
  const body = await response.json();

  cache.put(cacheKey, new Response(JSON.stringify(body), { status: 200 }));

  return event.respondWith(new Response(JSON.stringify(body), { status: 200 }));
});